export default async function handler(req, res) {
  // CORS Настройки
  res.setHeader('Access-Control-Allow-Credentials', true);
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,OPTIONS,PATCH,DELETE,POST,PUT');
  res.setHeader(
    'Access-Control-Allow-Headers',
    'X-CSRF-Token, X-Requested-With, Accept, Accept-Version, Content-Length, Content-MD5, Content-Type, Date, X-Api-Version'
  );

  if (req.method === 'OPTIONS') {
    res.status(200).end();
    return;
  }

  if (req.method !== 'POST') {
    res.status(405).json({ error: 'Метод не поддерживается' });
    return;
  }

  try {
    const { messages } = req.body;

    const contents = messages.map(msg => ({
      role: msg.role === 'model' ? 'model' : 'user',
      parts: [{ text: msg.text }]
    }));

    const apiKey = process.env.VITE_API_KEY || process.env.API_KEY;

    if (!apiKey) {
       res.status(500).json({ error: 'Конфигурация сервера: отсутствует API ключ' });
       return;
    }

    const systemInstruction = {
      parts: [{
        text: `Ты — Shou AI, специализированный ассистент профессионального трейдера Danya.shou. 
Твои правила:
1. Темы: Трейдинг, крипта, финансы, психология рынка, Smart Money, Price Action.
2. На посторонние темы (быт, еда, политика) отвечать ЗАПРЕЩЕНО. Вежливо напомни о своей специализации.
3. Стиль: Профессиональный, лаконичный, дисциплинированный, "холодный" аналитический ум.
4. Язык: Всегда отвечай на русском.
5. Не давай финансовых советов, только аналитику и обучение на основе методов Danya.shou.`
      }]
    };

    const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${apiKey}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        systemInstruction: systemInstruction,
        contents: contents,
        generationConfig: {
            temperature: 0.7,
            topK: 40,
            topP: 0.95,
            maxOutputTokens: 1024,
        }
      })
    });

    const data = await response.json();

    if (!response.ok) {
        console.error("Google API Error:", data);
        res.status(response.status).json({ 
            error: data.error?.message || 'Ошибка API Google',
            details: data 
        });
        return;
    }

    res.status(200).json(data);

  } catch (error) {
    console.error("Proxy Crash:", error);
    res.status(500).json({ error: 'Внутренняя ошибка прокси-сервера' });
  }
}

