import React, { useEffect, useState, useMemo } from 'react';

interface Sparkle {
  id: number;
  x: number;
  y: number;
  size: number;
  duration: number;
  delay: number;
}

const Sparkles: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [sparkles, setSparkles] = useState<Sparkle[]>([]);

  useEffect(() => {
    const generateSparkles = () => {
      const newSparkles = Array.from({ length: 20 }).map((_, i) => ({
        id: i,
        x: Math.random() * 120 - 10, // Дистанция вокруг текста
        y: Math.random() * 120 - 10,
        size: Math.random() * 3 + 1,
        duration: Math.random() * 2 + 1,
        delay: Math.random() * 5,
      }));
      setSparkles(newSparkles);
    };

    generateSparkles();
  }, []);

  return (
    <div className="relative inline-block">
      {sparkles.map((sparkle) => (
        <div
          key={sparkle.id}
          className="absolute bg-white rounded-full pointer-events-none z-0 animate-sparkle"
          style={{
            left: `${sparkle.x}%`,
            top: `${sparkle.y}%`,
            width: `${sparkle.size}px`,
            height: `${sparkle.size}px`,
            opacity: 0,
            boxShadow: '0 0 10px #fff, 0 0 20px #fff',
            animation: `sparkle ${sparkle.duration}s ease-in-out ${sparkle.delay}s infinite`,
          }}
        />
      ))}
      <style>{`
        @keyframes sparkle {
          0% { transform: translateY(0) scale(0); opacity: 0; }
          50% { opacity: 1; transform: translateY(-20px) scale(1.2); }
          100% { transform: translateY(-40px) scale(0); opacity: 0; }
        }
      `}</style>
      <div className="relative z-10">
        {children}
      </div>
    </div>
  );
};

export default Sparkles;

