  useEffect(() => {
    const generateSparkles = () => {
      // Увеличиваем количество для более плотного эффекта
      const newSparkles = Array.from({ length: 45 }).map((_, i) => ({
        id: i,
        // Расширяем диапазон от -25% до 125%, чтобы искры выходили за границы текста равномерно
