import React, { useEffect, useRef, useState } from 'react';

const CustomCursor: React.FC = () => {
  const cursorRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isHovering, setIsHovering] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    let animationId: number;

    let mouseX = window.innerWidth / 2;
    let mouseY = window.innerHeight / 2;
    let realMouseX = mouseX;
    let realMouseY = mouseY;

    const trail: {x: number, y: number}[] = [];
    const TRAIL_LENGTH = 12; // Чуть короче для большей четкости

    const resize = () => {
      if (canvas) {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', resize);
    resize();

    const handleMouseMove = (e: MouseEvent) => {
      realMouseX = e.clientX;
      realMouseY = e.clientY;

      // Мгновенное обновление позиции точки для нулевой задержки
      if (cursorRef.current) {
        cursorRef.current.style.transform = `translate3d(${realMouseX}px, ${realMouseY}px, 0) translate(-50%, -50%)`;
      }

      const target = e.target as HTMLElement;
      const isClickable = 
        target.tagName === 'A' || 
        target.tagName === 'BUTTON' || 
        target.closest('a') || 
        target.closest('button') ||
        target.classList.contains('cursor-pointer');

      setIsHovering(!!isClickable);
    };

    const render = () => {
      if (!canvas || !ctx) return;

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Увеличен коэффициент с 0.15 до 0.45 для мгновенного отклика
      // Теперь шлейф "летит" за мышкой без вязкости
      mouseX += (realMouseX - mouseX) * 0.45;
      mouseY += (realMouseY - mouseY) * 0.45;

      const jitterX = (Math.random() - 0.5) * 1.2;
      const jitterY = (Math.random() - 0.5) * 1.2;

      trail.push({ x: mouseX + jitterX, y: mouseY + jitterY });

      if (trail.length > TRAIL_LENGTH) {
        trail.shift();
      }

      if (trail.length > 1) {
        ctx.beginPath();
        ctx.moveTo(trail[0].x, trail[0].y);

        for (let i = 1; i < trail.length - 1; i++) {
          const xc = (trail[i].x + trail[i+1].x) / 2;
          const yc = (trail[i].y + trail[i+1].y) / 2;
          ctx.quadraticCurveTo(trail[i].x, trail[i].y, xc, yc);
        }

        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.lineWidth = isHovering ? 2 : 1;

        const gradient = ctx.createLinearGradient(trail[0].x, trail[0].y, realMouseX, realMouseY);
        gradient.addColorStop(0, 'rgba(255, 255, 255, 0)');
        gradient.addColorStop(1, 'rgba(255, 255, 255, 0.8)');

        ctx.shadowBlur = isHovering ? 20 : 8;
        ctx.shadowColor = '#fff';
        ctx.strokeStyle = gradient;
        ctx.stroke();
      }

      animationId = requestAnimationFrame(render);
    };

    window.addEventListener('mousemove', handleMouseMove, { passive: true });
    animationId = requestAnimationFrame(render);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationId);
    };
  }, [isHovering]);

  return (
    <>
      <canvas 
        ref={canvasRef}
        className="pointer-events-none fixed inset-0 z-[9998] opacity-70"
      />

      <div 
        ref={cursorRef}
        className={`pointer-events-none fixed top-0 left-0 z-[9999] bg-white rounded-full mix-blend-difference transition-all duration-150 ease-out flex items-center justify-center ${
          isHovering ? 'w-12 h-12' : 'w-2.5 h-2.5'
        }`}
        style={{ transform: 'translate(-50%, -50%)', willChange: 'transform' }}
      >
        {isHovering && (
          <div className="w-1.5 h-1.5 bg-black rounded-full animate-pulse" />
        )}
      </div>
    </>
  );
};

