import React, { useState, useEffect, useRef } from 'react';
import { SECTIONS, SOCIAL_LINKS, TRADING_STATS, SKILL_DATA, PROJECTS_DATA, MEDIA_CONFIG } from './constants';
import Section from './components/Section';
import SocialCard from './components/SocialCard';
import ProjectCard from './components/ProjectCard';
import CustomCursor from './components/CustomCursor';
import Sparkles from './components/Sparkles';
import { 
  ChevronDown, 
  FolderCode, 
  ArrowLeft, 
  Volume2, 
  VolumeX, 
  Eye,
  MonitorPlay,
  Users,
  GraduationCap,
  Building2,
  Clock
} from 'lucide-react';
import { RadarChart, PolarGrid, PolarAngleAxis, Radar as RechartsRadar, ResponsiveContainer } from 'recharts';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<'main' | 'projects'>('main');
  const [activeSection, setActiveSection] = useState<string>('');
  const [isMuted, setIsMuted] = useState(true);
  const [volume, setVolume] = useState(0.5);
  const [hasInteracted, setHasInteracted] = useState(false);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  useEffect(() => {
    if (viewMode === 'main') {
      const timer = setTimeout(() => setActiveSection(SECTIONS[0].id), 100);
      return () => clearTimeout(timer);
    }
  }, [viewMode]);

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.muted = isMuted;
      audioRef.current.volume = volume;
      if (!isMuted && hasInteracted) {
        audioRef.current.play().catch(e => console.log("Autoplay blocked", e));
      }
    }
  }, [isMuted, hasInteracted, volume]);

  const toggleMute = () => {
    if (!hasInteracted) setHasInteracted(true);
    setIsMuted(!isMuted);
  };

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseFloat(e.target.value);
    setVolume(val);
    if (val > 0) setIsMuted(false);
    else setIsMuted(true);
    if (!hasInteracted) setHasInteracted(true);
  };

  const handleNavigation = (id: string) => {
    if (viewMode === 'projects') setViewMode('main');
    setTimeout(() => {
      const element = document.getElementById(id);
      if (element && scrollContainerRef.current) {
        element.scrollIntoView({ behavior: 'smooth' });
      }
    }, 50);
  };

  const roadmapPlans = [
    {
      icon: MonitorPlay,
      title: "Content Quality",
      desc: "Implement stable market reviews, conduct backtests, and scale educational content production.",
      status: "In Progress"
    },
    {
      icon: Users,
      title: "Mentorship 1/1",
      desc: "Personalized coaching on trading methodologies for maximum progress and deep market understanding.",
      status: "Active"
    },
    {
      icon: GraduationCap,
      title: "Trading School",
      desc: "A comprehensive school for beginners: systematic approach to learning and capital protection strategies.",
      status: "Developing"
    },
    {
      icon: Building2,
      title: "Offline Office",
      desc: "Opening a physical workspace for collaborative trading and knowledge sharing. Coming soon.",
      status: "Soon",
      isHighlight: true
    }
  ];

  return (
    <div className="bg-black text-white h-[100dvh] w-full relative overflow-hidden font-sans selection:bg-white/20 selection:text-white">
      <CustomCursor />

      {/* Background Layer */}
      <div className="absolute inset-0 z-0 overflow-hidden pointer-events-none">
        <video 
          autoPlay 
          loop 
          muted 
          playsInline 
          className="w-full h-full object-cover opacity-60 scale-100 transition-opacity duration-1000"
          style={{ 
            filter: 'contrast(1.3) brightness(0.75) grayscale(1)',
            imageRendering: 'crisp-edges'
          }}
        >
          <source src={MEDIA_CONFIG.videoUrl} type="video/mp4" />
        </video>

        <div className="absolute inset-0 bg-black/20" />

        {/* Analog Grain */}
        <div className="absolute inset-0 opacity-[0.08] mix-blend-screen overflow-hidden">
          <div className="absolute inset-[-200%] bg-repeat animate-grain" style={{ backgroundImage: `url('https://grainy-gradients.vercel.app/noise.svg')` }} />
        </div>

        {/* Technical Grid Overlay */}
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_40%,rgba(0,0,0,0.98)_100%)]" />

        <div 
          className="absolute inset-0 opacity-[0.03]" 
          style={{ 
            backgroundImage: `
              linear-gradient(to right, rgba(255,255,255,0.05) 1px, transparent 1px),
              linear-gradient(to bottom, rgba(255,255,255,0.05) 1px, transparent 1px)
            `,
            backgroundSize: '12px 12px' 
          }} 
        />
      </div>

      <style>{`
        @keyframes grain {
          0%, 100% { transform: translate(0, 0); }
          10% { transform: translate(-1%, -2%); }
          20% { transform: translate(-4%, 1%); }
          30% { transform: translate(2%, -4%); }
          40% { transform: translate(-1%, 4%); }
          50% { transform: translate(-3%, 2%); }
        }
        .animate-grain {
          animation: grain 0.8s steps(1) infinite;
        }
        input[type='range']::-webkit-slider-thumb {
          -webkit-appearance: none;
          appearance: none;
          width: 8px;
          height: 8px;
          background: #fff;
          cursor: pointer;
          border-radius: 50%;
        }
      `}</style>

      <audio ref={audioRef} src={MEDIA_CONFIG.audioUrl} loop />

      {/* Dynamic Header */}
      <header className="fixed top-0 left-0 w-full p-6 md:p-10 z-[100] flex justify-between items-start pointer-events-none">
        <div className="flex flex-col gap-3 md:gap-4 pointer-events-auto">
          <div className="flex items-center gap-2 md:gap-3 group/audio">
            <button 
              onClick={toggleMute}
              className="p-2 md:p-3 bg-white/5 hover:bg-white/10 backdrop-blur-md rounded-full border border-white/10 transition-all flex items-center justify-center shadow-2xl"
            >
              {isMuted || volume === 0 ? (
                <VolumeX size={16} className="text-white/30 md:w-[18px]" />
              ) : (
                <Volume2 size={16} className="text-white animate-pulse md:w-[18px]" />
              )}
            </button>

            <div className="w-0 overflow-hidden group-hover/audio:w-20 md:group-hover/audio:w-28 group-hover/audio:ml-2 transition-all duration-500 ease-out flex items-center bg-white/5 backdrop-blur-md px-0 group-hover/audio:px-3 rounded-full border border-transparent group-hover/audio:border-white/10 h-8 md:h-10">
              <input 
                type="range"
                min="0"
                max="1"
                step="0.01"
                value={isMuted ? 0 : volume}
                onChange={handleVolumeChange}
                className="w-full h-1 bg-white/20 rounded-full appearance-none cursor-pointer accent-white"
              />
            </div>
          </div>

          <div className="flex flex-col cursor-pointer group pointer-events-auto" onClick={() => handleNavigation('personality')}>
            <span className="text-[7px] md:text-[9px] font-mono font-bold tracking-[0.3em] md:tracking-[0.5em] text-white/80 group-hover:text-white transition-all duration-500 uppercase">
