import React, { useEffect, useRef, useState } from 'react';

interface ClickEffect {
  x: number;
  y: number;
  id: number;
  startTime: number;
  particles: {
    vx: number;
    vy: number;
    size: number;
    color: string;
  }[];
}

const CustomCursor: React.FC = () => {
  const cursorRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isHovering, setIsHovering] = useState(false);
  const [isClicked, setIsClicked] = useState(false);
  const clickEffectsRef = useRef<ClickEffect[]>([]);
  const nextEffectId = useRef(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    let animationId: number;

    let mouseX = window.innerWidth / 2;
    let mouseY = window.innerHeight / 2;
    let realMouseX = mouseX;
    let realMouseY = mouseY;

    const trail: {x: number, y: number}[] = [];
    const TRAIL_LENGTH = 8;

    const resize = () => {
      if (canvas) {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', resize);
    resize();

    const handleMouseMove = (e: MouseEvent) => {
      realMouseX = e.clientX;
      realMouseY = e.clientY;

      if (cursorRef.current) {
        cursorRef.current.style.transform = `translate3d(${realMouseX}px, ${realMouseY}px, 0) translate(-50%, -50%)`;
      }

      const target = e.target as HTMLElement;
      const isClickable = 
        target.tagName === 'A' || 
        target.tagName === 'BUTTON' || 
        target.closest('a') || 
        target.closest('button') ||
        target.classList.contains('cursor-pointer');

      setIsHovering(!!isClickable);
    };

    const handleMouseDown = (e: MouseEvent) => {
      if (e.button !== 0) return; // Only left click
      setIsClicked(true);

      // Add new click effect
      const particles = Array.from({ length: 8 }).map(() => ({
        vx: (Math.random() - 0.5) * 12,
        vy: (Math.random() - 0.5) * 12,
        size: Math.random() * 3 + 1,
        color: Math.random() > 0.5 ? '#ffffff' : 'rgba(255,255,255,0.5)'
      }));

      clickEffectsRef.current.push({
        x: e.clientX,
        y: e.clientY,
        id: nextEffectId.current++,
        startTime: performance.now(),
        particles
      });

      // Limit concurrent effects for performance
      if (clickEffectsRef.current.length > 5) {
        clickEffectsRef.current.shift();
      }
    };

    const handleMouseUp = () => setIsClicked(false);

    const render = (time: number) => {
      if (!canvas || !ctx) return;

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // --- Cursor Trail ---
      mouseX += (realMouseX - mouseX) * 0.85;
      mouseY += (realMouseY - mouseY) * 0.85;

      const jitterX = (Math.random() - 0.5) * 0.8;
      const jitterY = (Math.random() - 0.5) * 0.8;

      trail.push({ x: mouseX + jitterX, y: mouseY + jitterY });

      if (trail.length > TRAIL_LENGTH) {
        trail.shift();
      }

      if (trail.length > 1) {
        ctx.beginPath();
        ctx.moveTo(trail[0].x, trail[0].y);

        for (let i = 1; i < trail.length - 1; i++) {
          const xc = (trail[i].x + trail[i+1].x) / 2;
          const yc = (trail[i].y + trail[i+1].y) / 2;
          ctx.quadraticCurveTo(trail[i].x, trail[i].y, xc, yc);
        }

        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.lineWidth = isHovering ? 2.5 : 1.5;

        const gradient = ctx.createLinearGradient(trail[0].x, trail[0].y, realMouseX, realMouseY);
        gradient.addColorStop(0, 'rgba(255, 255, 255, 0)');
        gradient.addColorStop(1, 'rgba(255, 255, 255, 0.9)');

        ctx.shadowBlur = isHovering ? 15 : 5;
        ctx.shadowColor = '#fff';
        ctx.strokeStyle = gradient;
        ctx.stroke();
        ctx.shadowBlur = 0;
      }

      // --- Click Effects ---
      clickEffectsRef.current = clickEffectsRef.current.filter(effect => {
        const elapsed = time - effect.startTime;
        const duration = 600; // ms
        const progress = elapsed / duration;

        if (progress >= 1) return false;

        // 1. Expanding HUD Ring
        const ringRadius = progress * 60;
        const opacity = 1 - progress;
        ctx.beginPath();
        ctx.arc(effect.x, effect.y, ringRadius, 0, Math.PI * 2);
        ctx.strokeStyle = `rgba(255, 255, 255, ${opacity * 0.5})`;
        ctx.lineWidth = 1;
        ctx.stroke();

        // 2. Corner Brackets expanding
        const bracketSize = progress * 40;
        const offset = progress * 20;
        ctx.strokeStyle = `rgba(255, 255, 255, ${opacity * 0.3})`;
        // Top-left bracket
        ctx.beginPath();
        ctx.moveTo(effect.x - offset - 5, effect.y - offset);
        ctx.lineTo(effect.x - offset, effect.y - offset);
        ctx.lineTo(effect.x - offset, effect.y - offset - 5);
        ctx.stroke();

        // 3. Particles (Squares)
        effect.particles.forEach(p => {
          const px = effect.x + p.vx * progress * 5;
          const py = effect.y + p.vy * progress * 5;
          const pOpacity = (1 - progress) * 0.8;

          ctx.fillStyle = p.color === '#ffffff' ? `rgba(255, 255, 255, ${pOpacity})` : `rgba(255, 255, 255, ${pOpacity * 0.5})`;
          ctx.fillRect(px - p.size/2, py - p.size/2, p.size, p.size);
        });

        return true;
      });

      animationId = requestAnimationFrame(render);
    };

    window.addEventListener('mousemove', handleMouseMove, { passive: true });
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);
    animationId = requestAnimationFrame(render);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationId);
    };
  }, [isHovering]);

  return (
    <>
      <canvas 
        ref={canvasRef}
        className="pointer-events-none fixed inset-0 z-[9998] opacity-80"
      />

      <div 
        ref={cursorRef}
        className={`pointer-events-none fixed top-0 left-0 z-[9999] bg-white rounded-full mix-blend-difference transition-all duration-150 ease-out flex items-center justify-center ${
          isHovering ? (isClicked ? 'w-8 h-8' : 'w-10 h-10') : (isClicked ? 'w-1 h-1' : 'w-2 h-2')
        }`}
        style={{ 
          transform: 'translate(-50%, -50%)', 
          willChange: 'transform',
          boxShadow: isClicked ? '0 0 15px #fff' : 'none'
        }}
      >
        {isHovering && (
          <div className={`bg-black rounded-full transition-all duration-150 ${isClicked ? 'w-0.5 h-0.5' : 'w-1 h-1'}`} />
        )}
      </div>
    </>
  );
};

